usage_examples.frontend_switch:
// Example frontend usage
switch (error.code) {
  case 0x1500:
    showStudentAction('Submit your transcript to the university portal first');
    break;
  case 0x1300:
    showStudentAction('Contact your university financial aid office for details');
    break;
  case 0x1200:
    showStudentAction('Wait for next funding cycle or contact your sponsor');
    break;
  default:
    showGenericError('Transaction failed. Please try again.');
}

usage_examples.error_mapping:
const ERROR_MAPPING = {
  0x1500: 'Submit your transcript to the university portal first',
  0x1300: 'Contact your university financial aid office for details',
  0x1200: 'Wait for next funding cycle or contact your sponsor'
};

function getStudentAction(errorCode) {
  return ERROR_MAPPING[errorCode] || 'Contact support for assistance';
}
